content.value:
.container {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;  /* তিনটি সমান কলাম */
  grid-template-rows: auto;
  gap: 20px;
}

.item {
  grid-column: 1 / 3;   /* ১ থেকে ৩ নম্বর লাইন পর্যন্ত বিস্তৃত */
  grid-row: 1 / 2;
}

.container {
  display: grid;
  grid-template-columns: 200px 1fr;
  grid-template-areas:
    "sidebar header"
    "sidebar main"
    "sidebar footer";
}
.sidebar { grid-area: sidebar; }
.header  { grid-area: header; }
.main    { grid-area: main; }
.footer  { grid-area: footer; }

.gallery {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
  gap: 10px;
}
